import json

# Read the list of all symbols that are financially troubled
financial_troubled = locals().get('var_functions.query_db:2', [])
symbol_map = {}
for row in financial_troubled:
    symbol = row['Symbol']
    # Extract company name
    desc = row['CompanyDescription']
    if ' specializes in' in desc:
        company_name = desc.split(' specializes in')[0]
    elif ' is an ' in desc:
        company_name = desc.split(' is an ')[0]
    elif ' is a ' in desc:
        company_name = desc.split(' is a ')[0]
    elif ' is at the forefront' in desc:
        company_name = desc.split(' is at the forefront')[0]
    elif ' provides' in desc:
        company_name = desc.split(' provides')[0]
    else:
        company_name = desc

    symbol_map[symbol] = company_name.strip().rstrip('.')

# Build a list of all symbols we need to check
all_symbols = list(symbol_map.keys())
symbols_to_check = [s for s in all_symbols if s not in ['FTR', 'IDEX', 'APEX', 'BIOC', 'AGMH', 'AMTX', 'FAMI', 'SPI']]

print('__RESULT__:')
print(json.dumps({
    'symbols_remaining': symbols_to_check,
    'total_to_check': len(symbols_to_check),
    'company_names': symbol_map
}))

